// ════════════════════════════════════════════════════════
// CFO MEMORY INGEST — Validate & Prepare v1.0
// Valide l'entrée, enrichit le texte et formate le document
// au format LangChain attendu par vectorStorePGVector (insert mode).
// ════════════════════════════════════════════════════════
const body = $input.first().json.body || $input.first().json;

const texte      = (body.texte || body.text || '').trim();
const categorie  = (body.categorie || body.category || 'general').toLowerCase();
const session_id = body.session_id || 'unknown';

const VALID_CATS = ['preference', 'regle', 'contexte', 'general'];

if (!texte || texte.length < 5) {
  throw new Error('Texte vide ou trop court (min 5 caractères).');
}
if (!VALID_CATS.includes(categorie)) {
  throw new Error('Catégorie invalide: ' + categorie + '. Autorisées: ' + VALID_CATS.join(', '));
}

// Enrichissement du texte : préfixe structuré pour améliorer le rappel RAG
const date_iso = new Date().toISOString().slice(0, 10);
const texte_enrichi = `[CFO-MEMORY | ${categorie.toUpperCase()} | ${date_iso}]\n${texte}`;

// Format LangChain Document attendu par vectorStorePGVector en mode insert
return [{
  json: {
    pageContent: texte_enrichi,
    metadata: {
      categorie,
      session_id,
      source: 'cfo_agent_memory_writer',
      texte_original: texte,
      date_ingestion: new Date().toISOString()
    }
  }
}];
